// CF13 WF_PREDICT_PERFORMANCE — normalize trigger, idempotency check,
// fetch topic + project + pps_config. Global fetch + $env per MEMORY.md.

const raw = $input.first().json;
const viaWebhook = !!raw.body;
const payload = raw.body || raw;

const topicId = payload.topic_id;
const force = payload.force === true;

if (!topicId) {
  return [{
    json: {
      success: false,
      error: 'Provide { topic_id }',
      http_status: 400,
      via_webhook: viaWebhook
    }
  }];
}

const supabaseUrl = $env.SUPABASE_URL;
const sbHeaders = {
  'apikey': $env.SUPABASE_ANON_KEY,
  'Authorization': `Bearer ${$env.SUPABASE_SERVICE_ROLE_KEY}`,
  'Content-Type': 'application/json'
};

async function sbGet(url, label) {
  const res = await fetch(url, { method: 'GET', headers: sbHeaders });
  if (!res.ok) throw new Error(`${label} failed: HTTP ${res.status}: ${(await res.text()).slice(0, 200)}`);
  return res.json();
}

// 1. Fetch topic with all PPS input columns
const topicUrl = `${supabaseUrl}/rest/v1/topics?id=eq.${topicId}&select=id,project_id,seo_title,selected_title,outlier_score,seo_score,script_quality_score,thumbnail_ctr_score,title_ctr_score,predicted_performance_score,pps_light,pps_recommendation,pps_breakdown,pps_missing_inputs,pps_calculated_at`;
const topics = await sbGet(topicUrl, 'fetch topic');
const topic = Array.isArray(topics) && topics[0] ? topics[0] : null;

if (!topic) {
  return [{ json: { success: false, error: `Topic ${topicId} not found`, http_status: 404, via_webhook: viaWebhook } }];
}

// 2. Idempotency: if already calculated and not forced, return existing row
if (!force && topic.pps_calculated_at) {
  return [{
    json: {
      success: true,
      skipped: true,
      reason: 'PPS already calculated (pass force=true to recompute)',
      topic_id: topicId,
      project_id: topic.project_id,
      predicted_performance_score: topic.predicted_performance_score,
      pps_light: topic.pps_light,
      pps_recommendation: topic.pps_recommendation,
      pps_breakdown: topic.pps_breakdown,
      pps_missing_inputs: topic.pps_missing_inputs,
      pps_calculated_at: topic.pps_calculated_at,
      http_status: 200,
      via_webhook: viaWebhook
    }
  }];
}

const projectId = topic.project_id;

// 3. Fetch project context (niche_health_score may not exist yet — migration 010 default 50)
let project = {};
try {
  const projArr = await sbGet(`${supabaseUrl}/rest/v1/projects?id=eq.${projectId}&select=niche,niche_description,niche_health_score`, 'fetch project');
  project = (projArr && projArr[0]) || {};
} catch (_) { /* non-fatal — CF11 may not be live */ }

// 4. Fetch pps_config — seeded row exists per migration 013
let ppsConfig = null;
try {
  const cfgArr = await sbGet(`${supabaseUrl}/rest/v1/pps_config?project_id=eq.${projectId}&limit=1&select=outlier_weight,seo_weight,script_quality_weight,niche_health_weight,thumbnail_ctr_weight,title_ctr_weight`, 'fetch pps_config');
  ppsConfig = (cfgArr && cfgArr[0]) || null;
} catch (_) { /* will default */ }

// Default weights if config missing
if (!ppsConfig) {
  ppsConfig = {
    outlier_weight: 0.30,
    seo_weight: 0.20,
    script_quality_weight: 0.20,
    niche_health_weight: 0.15,
    thumbnail_ctr_weight: 0.10,
    title_ctr_weight: 0.05
  };
}

return [{
  json: {
    topic_id: topicId,
    project_id: projectId,
    topic,
    project,
    pps_config: ppsConfig,
    via_webhook: viaWebhook,
    force,
    started_at: new Date().toISOString()
  }
}];

// Compute weighted PPS, classify light, build breakdown, generate natural-language
// recommendation via Claude Opus 4.6. Inline backoff on Anthropic call.

const data = $input.first().json;
if (data.success === false || data.skipped) return $input.item;

const anthropicKey = $env.ANTHROPIC_API_KEY;
const sleep = (ms) => new Promise(r => setTimeout(r, ms));

const topic = data.topic || {};
const project = data.project || {};
const cfg = data.pps_config || {};

const seoTitle = topic.selected_title || topic.seo_title || '(untitled)';

// 1. Normalize each factor to 0-100 scale. Track which inputs are fallback.
const missing = [];

const outlierRaw = topic.outlier_score;
const outlierIsFallback = outlierRaw === null || outlierRaw === undefined;
const outlierNorm = outlierIsFallback ? 50 : Math.max(0, Math.min(100, Number(outlierRaw)));
if (outlierIsFallback) missing.push('outlier_score');

const seoRaw = topic.seo_score;
const seoIsFallback = seoRaw === null || seoRaw === undefined;
const seoNorm = seoIsFallback ? 50 : Math.max(0, Math.min(100, Number(seoRaw)));
if (seoIsFallback) missing.push('seo_score');

// script_quality_score is DECIMAL(3,1) 0-10 scale → multiply by 10
const sqRaw = topic.script_quality_score;
const sqIsFallback = sqRaw === null || sqRaw === undefined;
const sqNorm = sqIsFallback ? 50 : Math.max(0, Math.min(100, Number(sqRaw) * 10));
if (sqIsFallback) missing.push('script_quality_score');

// niche_health_score — CF11 not live yet; default 50
const nhRaw = project.niche_health_score;
const nhIsFallback = nhRaw === null || nhRaw === undefined;
const nhNorm = nhIsFallback ? 50 : Math.max(0, Math.min(100, Number(nhRaw)));
if (nhIsFallback) missing.push('niche_health_score');

const tnRaw = topic.thumbnail_ctr_score;
const tnIsFallback = tnRaw === null || tnRaw === undefined;
const tnNorm = tnIsFallback ? 50 : Math.max(0, Math.min(100, Number(tnRaw)));
if (tnIsFallback) missing.push('thumbnail_ctr_score');

const ttRaw = topic.title_ctr_score;
const ttIsFallback = ttRaw === null || ttRaw === undefined;
const ttNorm = ttIsFallback ? 50 : Math.max(0, Math.min(100, Number(ttRaw)));
if (ttIsFallback) missing.push('title_ctr_score');

// 2. Apply weights
const wOutlier = Number(cfg.outlier_weight) || 0.30;
const wSeo = Number(cfg.seo_weight) || 0.20;
const wSq = Number(cfg.script_quality_weight) || 0.20;
const wNh = Number(cfg.niche_health_weight) || 0.15;
const wTn = Number(cfg.thumbnail_ctr_weight) || 0.10;
const wTt = Number(cfg.title_ctr_weight) || 0.05;

const contribOutlier = outlierNorm * wOutlier;
const contribSeo = seoNorm * wSeo;
const contribSq = sqNorm * wSq;
const contribNh = nhNorm * wNh;
const contribTn = tnNorm * wTn;
const contribTt = ttNorm * wTt;

const ppsRaw = contribOutlier + contribSeo + contribSq + contribNh + contribTn + contribTt;
const pps = Math.max(0, Math.min(100, Math.round(ppsRaw)));

// 3. Classify light
let light;
if (pps >= 75) light = 'green';
else if (pps >= 55) light = 'yellow';
else light = 'red';

// 4. Build breakdown — per-factor {raw, normalized, weight, contribution, is_fallback}
const factorDefs = [
  { key: 'outlier', label: 'Outlier', raw: outlierRaw, norm: outlierNorm, weight: wOutlier, contrib: contribOutlier, fallback: outlierIsFallback },
  { key: 'seo', label: 'SEO', raw: seoRaw, norm: seoNorm, weight: wSeo, contrib: contribSeo, fallback: seoIsFallback },
  { key: 'script_quality', label: 'Script Quality', raw: sqRaw, norm: sqNorm, weight: wSq, contrib: contribSq, fallback: sqIsFallback },
  { key: 'niche_health', label: 'Niche Health', raw: nhRaw, norm: nhNorm, weight: wNh, contrib: contribNh, fallback: nhIsFallback },
  { key: 'thumbnail_ctr', label: 'Thumbnail CTR', raw: tnRaw, norm: tnNorm, weight: wTn, contrib: contribTn, fallback: tnIsFallback },
  { key: 'title_ctr', label: 'Title CTR', raw: ttRaw, norm: ttNorm, weight: wTt, contrib: contribTt, fallback: ttIsFallback }
];

const breakdown = {};
for (const f of factorDefs) {
  breakdown[f.key] = {
    raw: f.raw === null || f.raw === undefined ? null : Number(f.raw),
    normalized: Math.round(f.norm * 10) / 10,
    weight: Math.round(f.weight * 1000) / 1000,
    contribution: Math.round(f.contrib * 10) / 10,
    is_fallback: f.fallback
  };
}

// Dragged-by: 2 lowest contributors by contribution
const sortedByContrib = [...factorDefs].sort((a, b) => a.contrib - b.contrib);
const draggedBy = sortedByContrib.slice(0, 2).map(f => f.label);
breakdown.dragged_by = draggedBy;

// 5. Build Opus recommendation prompt
const factorLines = factorDefs.map(f =>
  `- ${f.label} ${Math.round(f.norm)}/100 (weight ${f.weight})${f.fallback ? ' — fallback' : ''}`
).join('\n');

const recPrompt = `You are a YouTube growth advisor. Given this predicted performance score of ${pps}/100 (${light} light), write a 2-3 sentence recommendation focused on the top 2 drag factors.

Topic: ${seoTitle}
Score breakdown:
${factorLines}

Top drag factors: ${draggedBy.join(', ')}

If green (>=75): affirm strongly + 1 optimization opportunity.
If yellow (55-74): identify the specific fix that would push to green.
If red (<55): be blunt — either rework the specific weak factor or deprioritize this topic. No hedging.

Return only the recommendation text, no preamble.`;

async function callClaude(maxRetries = 4) {
  let lastErr = null;
  for (let attempt = 1; attempt <= maxRetries; attempt++) {
    try {
      const res = await fetch('https://api.anthropic.com/v1/messages', {
        method: 'POST',
        headers: {
          'x-api-key': anthropicKey,
          'anthropic-version': '2023-06-01',
          'content-type': 'application/json'
        },
        body: JSON.stringify({
          model: 'claude-opus-4-6',
          max_tokens: 350,
          messages: [{ role: 'user', content: recPrompt }]
        })
      });
      if (res.ok) {
        const body = await res.json();
        return { ok: true, text: body.content?.[0]?.text || '', attempts: attempt };
      }
      const errBody = await res.text();
      if (res.status === 429) await sleep(30000);
      lastErr = new Error(`HTTP ${res.status}: ${errBody.slice(0, 300)}`);
      if (res.status >= 400 && res.status < 500 && res.status !== 429) break;
    } catch (e) { lastErr = e; }
    if (attempt < maxRetries) await sleep(Math.min(1000 * Math.pow(2, attempt - 1), 30000));
  }
  return { ok: false, error: lastErr?.message || 'opus_recommendation failed', attempts: maxRetries };
}

const recStart = Date.now();
const recRes = await callClaude(4);

let recommendation;
if (recRes.ok && recRes.text.trim().length > 10) {
  recommendation = recRes.text.trim().slice(0, 2000);
} else {
  // Deterministic fallback based on light
  if (light === 'green') {
    recommendation = `Strong predicted performance at ${pps}/100. Consider tightening ${draggedBy[0].toLowerCase()} further before publishing for maximum reach.`;
  } else if (light === 'yellow') {
    recommendation = `Middling prediction at ${pps}/100. The biggest lift is fixing ${draggedBy[0]} and ${draggedBy[1]} — push those up and this becomes a green topic.`;
  } else {
    recommendation = `Weak prediction at ${pps}/100. Either rework ${draggedBy[0]} and ${draggedBy[1]} before publishing, or deprioritize this topic.`;
  }
}

const recCostUsd = recRes.ok ? 0.02 : 0;

return [{
  json: {
    ...data,
    pps,
    pps_light: light,
    pps_recommendation: recommendation,
    pps_breakdown: breakdown,
    pps_missing_inputs: missing,
    rec_ok: recRes.ok,
    rec_error: recRes.ok ? null : (recRes.error || 'fallback'),
    rec_duration_ms: Date.now() - recStart,
    rec_cost_usd: recCostUsd
  }
}];

// PATCH topic with PPS outputs. INSERT pps_calibration snapshot so S7 can backfill
// actuals and compute variance_pct. Log to production_logs.

const data = $input.first().json;
if (data.success === false) return [{ json: data }];
if (data.skipped) return [{ json: data }];

const supabaseUrl = $env.SUPABASE_URL;
const sbHeaders = {
  'apikey': $env.SUPABASE_ANON_KEY,
  'Authorization': `Bearer ${$env.SUPABASE_SERVICE_ROLE_KEY}`,
  'Content-Type': 'application/json'
};

const topicId = data.topic_id;
const projectId = data.project_id;
const nowIso = new Date().toISOString();

const patch = {
  predicted_performance_score: data.pps,
  pps_light: data.pps_light,
  pps_recommendation: data.pps_recommendation,
  pps_breakdown: data.pps_breakdown,
  pps_missing_inputs: data.pps_missing_inputs,
  pps_calculated_at: nowIso
};

let patchError = null;
try {
  const res = await fetch(`${supabaseUrl}/rest/v1/topics?id=eq.${topicId}`, {
    method: 'PATCH',
    headers: { ...sbHeaders, 'Prefer': 'return=minimal' },
    body: JSON.stringify(patch)
  });
  if (!res.ok) patchError = `PATCH failed: HTTP ${res.status}: ${(await res.text()).slice(0, 200)}`;
} catch (e) {
  patchError = e.message;
}

// Calibration snapshot — best-effort, non-fatal
let calibrationError = null;
try {
  const calRes = await fetch(`${supabaseUrl}/rest/v1/pps_calibration`, {
    method: 'POST',
    headers: { ...sbHeaders, 'Prefer': 'return=minimal' },
    body: JSON.stringify({
      topic_id: topicId,
      project_id: projectId,
      predicted_pps: data.pps,
      pps_breakdown: data.pps_breakdown,
      calibration_run_at: nowIso
    })
  });
  if (!calRes.ok) calibrationError = `calibration insert HTTP ${calRes.status}`;
} catch (e) {
  calibrationError = e.message;
}

// production_logs
try {
  await fetch(`${supabaseUrl}/rest/v1/production_logs`, {
    method: 'POST',
    headers: { ...sbHeaders, 'Prefer': 'return=minimal' },
    body: JSON.stringify({
      project_id: projectId,
      topic_id: topicId,
      stage: 'predict_performance',
      scene_number: null,
      action: 'pps_calculate',
      status: patchError ? 'partial' : (data.rec_ok ? 'success' : 'fallback'),
      duration_ms: data.rec_duration_ms || 0,
      cost_usd: data.rec_cost_usd || 0,
      retry_count: 0
    })
  });
} catch (_) { }

return [{
  json: {
    success: !patchError,
    topic_id: topicId,
    project_id: projectId,
    predicted_performance_score: data.pps,
    pps_light: data.pps_light,
    pps_recommendation: data.pps_recommendation,
    pps_breakdown: data.pps_breakdown,
    pps_missing_inputs: data.pps_missing_inputs,
    pps_calculated_at: nowIso,
    calibration_snapshotted: !calibrationError,
    calibration_error: calibrationError,
    rec_ok: data.rec_ok,
    rec_cost_usd: data.rec_cost_usd,
    patch_error: patchError,
    http_status: patchError ? 500 : 200,
    via_webhook: data.via_webhook
  }
}];
